// Comic generator — normalise form / command input.
const i = $input.first() ? ($input.first().json || {}) : {};
function pick(){ for(var k=0;k<arguments.length;k++){ var v=arguments[k]; if(v!=null && String(v).trim()!=='') return String(v).trim(); } return ''; }
// Topic / brief (any subject). Strip a leading /command if invoked programmatically.
let topic = pick(i['Topic / brief'], i['Topic'], i.topic, i.query, i.text).replace(/^\/[a-zA-Z]+\b/, '').trim();
if(!topic) topic = ($env.DEFAULT_AWARENESS_TOPIC || 'staying safe online');
const title = pick(i['Title'], i.title);
const style = pick(i['Art style'], i.style) || 'Cartoon';
const audience = pick(i['Audience'], i.audience) || 'General audience';
// Image quality (speed/cost lever): low | medium | high. Blank => art node uses
// COMIC_IMAGE_QUALITY or its default. "Faster"/"Best" labels map to low/high.
let quality = pick(i['Image quality'], i.quality).toLowerCase();
if (/fast|low/.test(quality)) quality = 'low';
else if (/high|best|max/.test(quality)) quality = 'high';
else if (/med|balanc/.test(quality)) quality = 'medium';
else quality = '';
// Scene descriptions: a textarea, one beat per line (optional). If present, the
// line count drives the panel count.
let scenes = [];
const rawScenes = pick(i['Scene descriptions'], i.scenes);
if (Array.isArray(i.scenes)) scenes = i.scenes.map(function(s){return String(s).trim();}).filter(Boolean);
else if (rawScenes) scenes = rawScenes.split(/\r?\n/).map(function(s){return s.replace(/^\s*\d+[).\-:]\s*/,'').trim();}).filter(Boolean);
const MAXP = parseInt($env.COMIC_MAX_PANELS || '12', 10) || 12;
let numScenes = scenes.length ? scenes.length : (parseInt(pick(i['Number of scenes'], i['Scenes'], i.numScenes), 10) || 6);
if (numScenes < 1) numScenes = 1; if (numScenes > MAXP) numScenes = MAXP;
if (scenes.length > MAXP) scenes = scenes.slice(0, MAXP);
return [{ json: {
  topic: topic, title: title, style: style, audience: audience, quality: quality,
  scenes: scenes, numScenes: numScenes,
  client: ($env.CLIENT_NAME || '').toString(),
  date: new Date().toISOString().slice(0,10)
} }];

