// Parse the AI comic script and build style-locked prompts for anchors + panels,
// plus the per-panel reference list (place + present characters) that drives the
// /images/edits consistency calls.
const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;               // Ollama
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text; // Claude
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json;
// The story (title, characters, panels, dialogue, captions, takeaways) MUST come
// from the AI model — we never fabricate narrative here. If parsing fails or the
// model returned no panels, fail loudly so the run is re-tried rather than shipping
// a placeholder comic with invented text.
if (!data || typeof data !== 'object' || !Array.isArray(data.panels) || !data.panels.length) {
  throw new Error('Comic: the AI did not return a usable comic script (no panels). ' +
    'Check the model/API key (CLAUDE_MODEL / AI_PROVIDER) and try again — the story text is written by the model, not the workflow.');
}
if (!data.title) data.title = r.title || ('A comic about ' + r.topic);

const STYLES = {
  'Cartoon': 'Playful flat 2D cartoon style, bold clean outlines, bright cel shading, simple appealing shapes.',
  'Anime / Manga': 'Anime/manga style, clean confident line art, expressive faces, cel shading, dynamic composition.',
  'American comic book': 'Classic American comic-book style, bold inked outlines, dramatic shading and halftones, saturated colour.',
  'Realistic / cinematic': 'Semi-realistic cinematic illustration, soft realistic lighting, rich detail, filmic colour grade.',
  'Watercolour': 'Soft watercolour illustration, painterly washes, gentle paper texture, warm palette.',
  'Noir ink (B&W)': 'High-contrast black-and-white noir ink style, heavy shadows, expressive crosshatching, no colour.',
  'Pixel art': '16-bit pixel-art style, crisp pixels, limited retro palette, clean dithering.',
  '3D (Pixar-style)': 'Polished 3D animated-film style, soft global illumination, rounded appealing characters.',
  'Flat vector': 'Modern flat vector illustration, clean geometric shapes, smooth gradients, minimal detail.'
};
const stylePreamble = (STYLES[r.style] || STYLES['Cartoon']) + ' Keep character designs, colours and the overall art style identical across every image. ';
const NEG = ' No text, no words, no letters, no numbers, no speech bubbles, no captions, no logos, no watermark, no UI.';
// Panels MAY contain speech-bubble text (gpt-image-2 renders it), but not chrome.
const NEGP = ' No logos, no watermark, no UI, no border, no caption box, no page numbers, no signature.';

const chars = Array.isArray(data.characters) ? data.characters : [];
const places = Array.isArray(data.places) ? data.places : [];
const charById = {}; chars.forEach(function(c){ if(c && c.id) charById[c.id] = c; });
const placeById = {}; places.forEach(function(p){ if(p && p.id) placeById[p.id] = p; });

const anchors = [];
chars.forEach(function(c){ if(!c) return; anchors.push({ id:'c_'+c.id, kind:'character', name:c.name||c.id,
  prompt: stylePreamble + 'Full-body character reference sheet of ' + (c.name||c.id) + (c.role?(' ('+c.role+')'):'') + ': ' + (c.visual||'') + '. Neutral standing pose, front view, plain light-grey studio background.' + NEG }); });
places.forEach(function(p){ if(!p) return; anchors.push({ id:'p_'+p.id, kind:'place', name:p.name||p.id,
  prompt: stylePreamble + 'Establishing wide shot of ' + (p.name||p.id) + ': ' + (p.visual||'') + '. No people present.' + NEG }); });

const panels = (Array.isArray(data.panels)?data.panels:[]).map(function(p, idx){
  p = p || {};
  const present = (Array.isArray(p.characters)?p.characters:[]).map(function(id){ return charById[id]; }).filter(Boolean);
  const place = placeById[p.place];
  const refIds = []; if (place) refIds.push('p_'+place.id); present.forEach(function(c){ refIds.push('c_'+c.id); });
  const who = present.length ? (' Characters present: ' + present.map(function(c){ return (c.name||c.id) + ' — ' + (c.visual||''); }).join('; ') + '.') : '';
  const where = place ? (' Setting: ' + (place.visual||place.name) + '.') : '';
  const dlg = (Array.isArray(p.dialogue)?p.dialogue:[]).slice(0,2).map(function(d){ return { speaker: (charById[d.speaker] && charById[d.speaker].name) || d.speaker || '', text: String(d.text||'').trim() }; }).filter(function(d){ return d.text; });
  // gpt-image-2 can render legible text — bake the dialogue into the panel as
  // real comic speech bubbles (the layout no longer overlays HTML bubbles).
  const speech = dlg.length ? (' Add classic comic speech bubbles, each containing EXACTLY this dialogue, spelled correctly and fully legible: ' + dlg.map(function(d){ return (d.speaker?(d.speaker+': '):'') + '"' + d.text + '"'; }).join('  ') + '. Place bubbles clear of faces; do not add any other text.') : '';
  const prompt = stylePreamble + ((p.shot?(p.shot+' shot. '):'')) + (p.action || p.scene || '') + where + who + ' Keep the character designs and setting consistent with these descriptions.' + speech + NEGP;
  return { index: idx+1, scene: p.scene||'', shot: p.shot||'medium', action: p.action||p.scene||'',
    caption: p.caption||'', dialogue: dlg,
    prompt: prompt, refIds: refIds };
});

const fileSafe = (String(data.title||r.topic).toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,40)) || 'comic';
const takeaways = (Array.isArray(data.takeaways)?data.takeaways:[]).map(function(t){ return String(t||'').trim(); }).filter(Boolean).slice(0,4);
// Custom header/cover banner in the SAME art style, based on the comic's content,
// so the masthead matches the chosen style instead of a generic gradient. Text-free
// (the title is overlaid by the layout for legibility).
const headerPrompt = stylePreamble + 'Dramatic wide cover-banner key art for a comic titled "' + (data.title||r.topic) + '" about ' + r.topic + '. ' + (data.logline||'') + ' Cinematic and eye-catching, capturing the theme and mood; keep the left portion less busy for a title overlay. No text, no words, no letters, no logos, no watermark, no UI.';
return [{ json: {
  data: data, stylePreamble: stylePreamble, anchors: anchors, panels: panels, headerPrompt: headerPrompt,
  title: data.title, logline: data.logline||'', brand: (r.client||''), topic: r.topic,
  style: r.style, audience: r.audience, date: r.date, fileSafe: fileSafe, takeaways: takeaways,
  quality: r.quality || ''
} }];

// Comic art generator — the consistency engine, hardened for n8n stability.
// 1) Generate a reference ("anchor") image per character and per place.
// 2) Generate each panel via /images/edits conditioned on that panel's anchors
//    (place + present characters) so designs/style stay consistent; falls back to
//    /images/generations.
// CRITICAL: images are written to a temp work dir on disk and only FILE PATHS are
// returned in JSON — never base64. That keeps n8n execution data tiny (a few KB
// instead of tens of MB of inline images), which is what was wedging n8n.
const fs = require('fs');
const H = this.helpers;
const j = $json || {};
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
const base = ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1');
const model = ($env.IMAGE_MODEL || 'gpt-image-1');
const size = ($env.COMIC_IMAGE_SIZE || '1024x1024');
// Image quality is the biggest speed/cost lever (gpt-image-1/2: low|medium|high|auto).
const QV = { low:1, medium:1, high:1, auto:1 };
let quality = String(j.quality || $env.COMIC_IMAGE_QUALITY || 'medium').toLowerCase();
if (!QV[quality]) quality = 'medium';
// Parallelism (bounded; default modest to stay light on memory & rate limits).
let conc = parseInt($env.COMIC_CONCURRENCY || '2', 10); if (!(conc > 0)) conc = 2; if (conc > 8) conc = 8;
// Per-call timeout — fail fast instead of hanging for minutes on a stuck call.
let timeout = parseInt($env.IMAGE_TIMEOUT || '90000', 10); if (!(timeout > 0)) timeout = 90000;
// Opt-in /images/edits (multipart) panel consistency; off by default for stability.
var useEdits = (($env.COMIC_USE_EDITS||'').toString().toLowerCase()==='true');

const baseName = (j.fileSafe || 'comic') + '-' + (j.date || new Date().toISOString().slice(0,10));
const workDir = '/reports/awareness/comics/.work/' + baseName;
const anchorsDir = workDir + '/anchors';
const panelsDir = workDir + '/panels';
try { fs.mkdirSync(anchorsDir, { recursive: true }); fs.mkdirSync(panelsDir, { recursive: true }); } catch (e) {}
if (key) { try { fs.writeFileSync(workDir + '/.w', 'ok'); fs.unlinkSync(workDir + '/.w'); } catch (e) { throw new Error('Comic: cannot write images to ' + workDir + '. Make /reports writable by the n8n container (e.g. `chmod -R a+rwX reports` on the host).'); } }

// Run an async fn over items with a fixed concurrency limit; preserves order.
async function mapLimit(items, limit, fn){
  const ret = new Array(items.length); let idx = 0;
  async function worker(){ while (idx < items.length){ const cur = idx++; ret[cur] = await fn(items[cur], cur); } }
  const n = Math.max(1, Math.min(limit, items.length));
  const workers = []; for (let w = 0; w < n; w++) workers.push(worker());
  await Promise.all(workers);
  return ret;
}
async function withRetry(fn){
  let lastErr;
  for (let attempt = 0; attempt < 2; attempt++){
    try { return await fn(); }
    catch (e) { lastErr = e; if (attempt === 0) await new Promise(function(r){ setTimeout(r, 1500); }); }
  }
  throw lastErr;
}

async function generate(prompt, sz){
  const resp = await withRetry(function(){ return H.httpRequest({ method:'POST', url: base + '/images/generations',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
    body: { model: model, prompt: prompt, size: (sz || size), quality: quality, n: 1 }, json: true, timeout: timeout }); });
  return resp && resp.data && resp.data[0] && resp.data[0].b64_json;
}
async function edit(prompt, refBuffers){
  const boundary = '----jarviscomic' + Date.now().toString(16) + Math.random().toString(16).slice(2);
  const CRLF = '\r\n'; const parts = [];
  function field(name, val){ parts.push(Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="' + name + '"' + CRLF + CRLF + String(val) + CRLF, 'utf8')); }
  function file(name, filename, buf){ parts.push(Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="' + name + '"; filename="' + filename + '"' + CRLF + 'Content-Type: image/png' + CRLF + CRLF, 'utf8')); parts.push(buf); parts.push(Buffer.from(CRLF, 'utf8')); }
  field('model', model); field('prompt', prompt); field('size', size); field('quality', quality); field('n', '1');
  for (let i = 0; i < refBuffers.length; i++) file('image[]', 'ref' + i + '.png', refBuffers[i]);
  parts.push(Buffer.from('--' + boundary + '--' + CRLF, 'utf8'));
  const body = Buffer.concat(parts);
  const resp = await H.httpRequest({ method:'POST', url: base + '/images/edits',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'multipart/form-data; boundary=' + boundary },
    body: body, json: false, timeout: timeout });
  const parsed = (typeof resp === 'string') ? JSON.parse(resp) : resp;
  return parsed && parsed.data && parsed.data[0] && parsed.data[0].b64_json;
}

let ok = 0, failed = 0;

// 1) Anchor reference images — independent, generated in parallel. Their buffers
//    are kept in memory (a handful) so panels can condition on them; the PNGs are
//    also written to disk for the final bundle.
const anchorImg = {};               // id -> Buffer (refs for panel edits)
const anchorsOut = await mapLimit(j.anchors || [], conc, async function(a){
  let buf = null;
  if (key) { try { const b64 = await generate(a.prompt); if (b64) buf = Buffer.from(b64, 'base64'); } catch (e) { buf = null; } }
  let file = '';
  if (buf) { file = anchorsDir + '/' + (a.id || 'anchor') + '.png'; try { fs.writeFileSync(file, buf); anchorImg[a.id] = buf; ok++; } catch (e) { file = ''; } }
  else if (key) failed++;
  return { id: a.id, name: a.name, kind: a.kind, file: file };
});

// 1b) Custom header/cover banner in the chosen art style (wide), based on the
//     comic's title/logline/topic — so the masthead matches the picked style.
let headerFile = '';
if (key && j.headerPrompt) {
  try { const b64 = await generate(j.headerPrompt, '1536x1024'); if (b64) { headerFile = workDir + '/header.png'; fs.writeFileSync(headerFile, Buffer.from(b64, 'base64')); ok++; } }
  catch (e) { headerFile = ''; }
}

// 2) Panels depend on the anchors but not each other → parallel. Write to disk and
//    return only the path; do NOT keep panel base64 in memory or JSON.
const panelsOut = await mapLimit(j.panels || [], conc, async function(p, idx){
  let buf = null;
  // Panels use plain /images/generations by default. The /images/edits multipart
  // upload (a binary Buffer pushed through the n8n task-runner proxy) can silently
  // crash the runner/process, so it is opt-in via COMIC_USE_EDITS=true. Visual
  // consistency comes from the detailed per-panel prompt (locked character/place
  // descriptions). When edits are enabled it falls back to generations on failure.
  const refs = (p.refIds || []).map(function(id){ return anchorImg[id]; }).filter(Boolean);
  if (key) {
    try {
      let b64 = '';
      if (useEdits && refs.length) { try { b64 = await edit(p.prompt, refs); } catch (e) { b64 = ''; } }
      if (!b64) b64 = await generate(p.prompt);
      if (b64) buf = Buffer.from(b64, 'base64');
    } catch (e) { buf = null; }
  }
  const num = String(p.index || idx + 1).padStart(2, '0');
  let file = '';
  if (buf) { file = panelsDir + '/panel-' + num + '.png'; try { fs.writeFileSync(file, buf); ok++; } catch (e) { file = ''; } }
  else if (key) failed++;
  // Keep only small layout fields in JSON (drop the long image prompt).
  return { index: p.index || idx + 1, shot: p.shot, action: p.action, scene: p.scene, caption: p.caption, dialogue: p.dialogue, file: file };
});

// Fail fast & loud if a key was configured but nothing came back — a red node with
// a clear cause beats a silent, hours-long run that yields a placeholder-only comic.
if (key && ok === 0) {
  throw new Error('Comic: image generation produced 0 images (' + failed + ' attempts failed). '
    + 'Check OpenAI image access/credits, IMAGE_MODEL="' + model + '", quality="' + quality + '", and network egress from the n8n container. '
    + 'Run stopped rather than producing a placeholder-only comic.');
}

return [{ json: {
  title: j.title, logline: j.logline, brand: j.brand, topic: j.topic, style: j.style,
  audience: j.audience, date: j.date, fileSafe: j.fileSafe, takeaways: j.takeaways || [], data: j.data || {},
  anchors: anchorsOut, panels: panelsOut, headerFile: headerFile, workDir: workDir,
  imageQuality: quality, concurrency: conc, generated: ok, failed: failed, hadKey: !!key
} }];

// Render the branded comic as one print-ready A4 HTML: a Jarvis-branded masthead, a
// 2-up panel grid with narration caption bars + speech bubbles, a Key-takeaways box
// (lessons learned, written by the AI) and a Jarvis sign-off. Works with real panel
// images or graceful placeholders. Gotenberg turns it into the PDF. Shares the brand
// kit (palette, avatar) with the magazine so everything looks and feels the same.
const j = $json || {};
const panels = j.panels || [];
const title = j.title || 'Comic';
const logline = j.logline || '';
const brand = (j.brand || '').toString();
const topic = (j.topic || '').toString();
const style = (j.style || '').toString();
const takeaways = (Array.isArray(j.takeaways) ? j.takeaways : []).map(function(t){ return String(t||'').trim(); }).filter(Boolean);
const date = j.date || new Date().toISOString().slice(0,10);
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }

// Shared brand kit — Jarvis avatar (prefer the branding file, else inline SVG) so the
// comic masthead/sign-off match the magazine and the Awareness Portal.
let _fs = null; try { _fs = require('fs'); } catch (e) {}
function avatarUri(){ if (_fs) { var t = [['/config/branding/jarvis-avatar.png','image/png'],['/config/branding/jarvis-avatar.jpg','image/jpeg'],['/config/branding/jarvis-avatar.jpeg','image/jpeg'],['/config/branding/jarvis-avatar.svg','image/svg+xml']]; for (var i=0;i<t.length;i++){ try { return 'data:' + t[i][1] + ';base64,' + _fs.readFileSync(t[i][0]).toString('base64'); } catch(e){} } } return ''; }
const JARVIS_SVG = '<svg class="av" viewBox="0 0 64 64" xmlns="http://www.w3.org/2000/svg"><defs><linearGradient id="jg" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#0E7C86"/><stop offset="1" stop-color="#0A1A2F"/></linearGradient></defs><circle cx="32" cy="32" r="32" fill="url(#jg)"/><rect x="19" y="21" width="26" height="22" rx="7" fill="#fff"/><circle cx="27" cy="32" r="3.2" fill="#0E7C86"/><circle cx="37" cy="32" r="3.2" fill="#0E7C86"/><rect x="27" y="38" width="10" height="2.4" rx="1.2" fill="#0E7C86"/><rect x="30.7" y="14" width="2.6" height="6" rx="1.3" fill="#9fe4d8"/><circle cx="32" cy="13" r="2.4" fill="#E7C76A"/><path d="M23 47h18l-3 4.5H26z" fill="#9fe4d8"/></svg>';
// Panel images live on disk (paths from the art node) — read each one lazily and
// inline it as a data URI only at render time, so images never travel through the
// node JSON. The resulting HTML is emitted as BINARY (below), not JSON.
function imgFromFile(file){ if (!file || !_fs) return ''; try { return 'data:image/png;base64,' + _fs.readFileSync(file).toString('base64'); } catch (e) { return ''; } }

function jbHex(v,d){v=String(v||'').trim();return /^#[0-9a-fA-F]{6}$/.test(v)?v:d;}
var JB_PRI=jbHex($env.BRAND_PRIMARY,'#0A1A2F'),JB_ACC=jbHex($env.BRAND_ACCENT,'#0E7C86'),JB_GOLD=jbHex($env.BRAND_GOLD,'#E7C76A');
const CSS = ":root{--jb-pri:"+JB_PRI+";--jb-acc:"+JB_ACC+";--jb-gold:"+JB_GOLD+"}@page{size:A4;margin:11mm} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,'Segoe UI',Roboto,Arial,sans-serif;color:#16202b}"
+".comic{width:100%}"
// masthead — Jarvis-branded, matches the magazine palette
+".mast{position:relative;background:radial-gradient(120% 130% at 88% -10%,#13507a 0,var(--jb-pri) 52%),linear-gradient(135deg,var(--jb-pri),var(--jb-acc) 160%);color:#fff;padding:13mm 15mm 11mm;overflow:hidden;border-radius:12px}"
+".mast .bg{position:absolute;inset:0;background-size:cover;background-position:center;z-index:0}"
+".mast .scrim{position:absolute;inset:0;z-index:1;background:linear-gradient(110deg,rgba(8,16,26,.92) 0%,rgba(8,16,26,.74) 44%,rgba(10,26,47,.40) 100%)}"
+".mast .row{display:flex;align-items:center;gap:13px;position:relative;z-index:2}"
+".mast .av{width:54px;height:54px;border-radius:50%;border:2px solid #9fe4d8;flex:0 0 auto;background:var(--jb-pri)}"
+".mast .av img,.mast .av svg{width:100%;height:100%;border-radius:50%;display:block}"
+".mast .brand{font-size:10pt;letter-spacing:3px;text-transform:uppercase;color:#9fe4d8;font-weight:800}"
